from flask import Flask, redirect, request, session, url_for
from requests_oauthlib import OAuth2Session
import os

app = Flask(__name__)
app.secret_key = os.urandom(24)

# OAuth 2.0 configuration
CLIENT_ID = 'your_client_id'
CLIENT_SECRET = 'your_client_secret'
AUTHORIZATION_BASE_URL = 'https://provider.com/oauth/authorize'
TOKEN_URL = 'https://provider.com/oauth/token'
DOMAIN = 'yourdomain.com'

@app.route('/login')
def login():
    redirect_uri = request.args.get('redirect_uri')
    
    if not redirect_uri or DOMAIN not in redirect_uri:
        return "Invalid redirect URI", 400
    
    session['redirect_uri'] = redirect_uri
    oauth = OAuth2Session(CLIENT_ID, redirect_uri=redirect_uri)
    authorization_url, state = oauth.authorization_url(AUTHORIZATION_BASE_URL)
    
    session['oauth_state'] = state
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    oauth = OAuth2Session(CLIENT_ID, state=session['oauth_state'])
    token = oauth.fetch_token(TOKEN_URL, client_secret=CLIENT_SECRET, authorization_response=request.url)
    
    # Store the token in the session or database as needed
    session['oauth_token'] = token
    return redirect(session.get('redirect_uri', url_for('index')))

@app.route('/')
def index():
    return "Welcome to the OAuth 2.0 Client Application"

if __name__ == '__main__':
    app.run(debug=True)